/**
 * Unit tests for the two-file default `IIntegrationSink` emitter (RFC-0002 §4, E1; #491).
 *
 * #491 — Shape C seam split: `generateSinkBase` emits `<entity>.sink.generated.ts`
 * (@generated, Shape C cast-free); `generateSinkSubclass` emits `<entity>.sink.ts`
 * (emit-once subclass with two one-line seam wirings).
 *
 * Pure-function tests — no filesystem. Cover:
 *   BASE (`generateSinkBase`):
 *   (a) FK-free entity → clean passthrough write, two standalone default functions,
 *       abstract SinkBase, no sentinel, @generated banner, NO ` as ` cast;
 *   (b) belongs_to FK entity → FK key as null + SEAM comment in defaultBuildWrite;
 *   (c) multi-word non-self FK + self-FK shapes → correct write-key verbatim;
 *   (d) json copy-through field → emits bare copy-through in both functions;
 *   (e) FK + json + userId together → all present, no cast;
 *   (f) non-`Integrated` pattern → hard-error naming the entity + `pattern: Integrated`;
 *   (g) provider literal is the bare slug;
 *   (h) §1b contract test — fkWriteKey() matches the template's relationKey+ExternalId;
 *   (i) #490 delete knob in concrete softDeleteByExternalId (delegate / noop);
 *   (j) #490 per-field exclusion (write vs. find view);
 *   (k) #491-specific: no CODEGEN-SCAFFOLD-V1 in base; no @Injectable;
 *       abstract seams declared; machinery in base NOT in subclass.
 *
 *   SUBCLASS (`generateSinkSubclass`):
 *   (l) carries the two one-line seam wirings (NOT an empty body — seams are abstract);
 *   (m) imports SinkBase + two default functions from the generated file;
 *   (n) does NOT carry integrationUpsertOne / findByExternalIdProjected (machinery is in base);
 *   (o) does NOT carry the CODEGEN-SCAFFOLD-V1 sentinel.
 *
 * #488 find-side projection tests (Tests 1–8 per spec) — now in `defaultToCanonicalView`:
 *   (1) Explicit view enumeration — not a bare `return row`.
 *   (2) Nullable scalars BARE — no `??` coercion (Gate 1.5 blocker guard).
 *   (3) Non-null scalars BARE — no `??`.
 *   (4) Json at `unknown` — no `as`, no `??`, SEAM marker present.
 *   (5) Timestamps enumerated iff `hasTimestamps`.
 *   (6) No ` as ` cast in any find-side case.
 *   (7) `findByExternalIdProjected` delegation unchanged (in base).
 *   (8) Banner documents generator-solved vs seam.
 */

import { describe, it, expect } from "bun:test";
import {
  generateSinkBase,
  generateSinkSubclass,
  type SinkEmitInput,
} from "../../cli/shared/sink-emission-generator";
import { fkWriteKey } from "../../cli/shared/adapter-emission-generator";

/** The "no ` as ` cast" rule (CLAUDE.md) is about the emitted *code*, not the
 *  English prose in doc comments (which legitimately contains the word "as").
 *  Strip whole-line `//` comments before asserting. The emitter never emits a
 *  trailing inline `// ...` on a code line, so whole-line stripping is exact. */
function codeOnly(src: string): string {
  return src
    .split("\n")
    .filter((line) => !line.trimStart().startsWith("//"))
    .join("\n");
}

/** FK-free `contact` (surface crm) — matches the integration-patterns fixture
 *  (`email` field only), promoted to `pattern: Integrated`. */
function contactInput(overrides: Partial<SinkEmitInput> = {}): SinkEmitInput {
  return {
    entityName: "contact",
    entityClass: "Contact",
    surface: "crm",
    pattern: "Integrated",
    provider: "hubspot",
    copyThroughFields: [{ camelName: "email", tsType: "string" }],
    fkExternalKeys: [],
    repoImportSpecifier: "../../../crm/contacts/contact.repository",
    ...overrides,
  };
}

// ============================================================================
// generateSinkBase — base file (@generated)
// ============================================================================

describe("generateSinkBase — FK-free entity: base file structure", () => {
  const out = generateSinkBase(contactInput());

  it("carries an @generated banner as the first line (NOT the CODEGEN-SCAFFOLD-V1 sentinel)", () => {
    // #491: the sentinel is DELETED from the sink emitter.
    expect(out).not.toContain("<CODEGEN-SCAFFOLD-V1>");
    expect(out).toContain("@generated by @pattern-stack/codegen");
  });

  it("emits the standalone defaultContactBuildWrite function at concrete types", () => {
    expect(out).toContain(
      "export function defaultContactBuildWrite(record: ContactIntegrationProjection): ContactIntegrationWrite {",
    );
  });

  it("emits the standalone defaultContactToCanonicalView function at concrete types", () => {
    expect(out).toContain(
      "export function defaultContactToCanonicalView(row: ContactIntegrationProjection): ContactIntegrationProjection {",
    );
  });

  it("emits abstract class ContactSinkBase<TCanonical = ContactIntegrationProjection>", () => {
    expect(out).toContain(
      "export abstract class ContactSinkBase<TCanonical = ContactIntegrationProjection>",
    );
  });

  it("implements IIntegrationSink<TCanonical>", () => {
    expect(out).toContain("implements IIntegrationSink<TCanonical>");
  });

  it("has NO extends bound on the type param (an extends bound rejects a widened canonical that drops a column)", () => {
    expect(out).not.toMatch(/TCanonical extends/);
  });

  it("has NO @Injectable decorator in code (OQ2 CLOSED — factory binding, decorator is dead)", () => {
    // The comment mentions @Injectable() (explaining why it's absent) — that's intentional.
    // Assert no `@Injectable()` decorator call appears in the code.
    expect(codeOnly(out)).not.toContain("@Injectable");
  });

  it("binds provider at construction (protected — not private)", () => {
    expect(out).toContain("protected readonly repo: ContactRepository,");
    expect(out).toContain("protected readonly provider: string,");
  });

  it("emits all three IIntegrationSink CONCRETE methods on the base", () => {
    expect(out).toContain(
      "async findByExternalId(userId: string, externalId: string): Promise<TCanonical | null>",
    );
    expect(out).toContain("async upsertByExternalId(");
    expect(out).toContain(
      "async softDeleteByExternalId(_userId: string, externalId: string): Promise<{ id: string } | null>",
    );
  });

  it("emits the two ABSTRACT seams with NO body", () => {
    expect(out).toContain(
      "protected abstract toCanonicalView(row: ContactIntegrationProjection): TCanonical;",
    );
    expect(out).toContain(
      "protected abstract buildWrite(record: TCanonical): ContactIntegrationWrite;",
    );
    // Seams must be abstract declarations — no opening brace follows them.
    const toCanonicalLine = out
      .split("\n")
      .find((l) => l.includes("protected abstract toCanonicalView"));
    const buildWriteLine = out
      .split("\n")
      .find((l) => l.includes("protected abstract buildWrite"));
    expect(toCanonicalLine?.trim()).not.toContain("{");
    expect(buildWriteLine?.trim()).not.toContain("{");
  });

  it("delegates repo calls in the concrete methods (findByExternalIdProjected / integrationUpsertOne / softDeleteByExternalId)", () => {
    expect(out).toContain(
      "this.repo.findByExternalIdProjected(externalId, this.provider)",
    );
    expect(out).toContain(
      "this.repo.integrationUpsertOne(this.buildWrite(record), this.provider)",
    );
    expect(out).toContain(
      "this.repo.softDeleteByExternalId(externalId, this.provider)",
    );
  });

  it("emits the provider-match assert that throws on mismatch", () => {
    expect(out).toContain("if (provider !== this.provider) {");
    expect(out).toContain(
      "ContactSink: bound provider '${this.provider}' != run provider '${provider}'",
    );
  });

  it("defaultContactBuildWrite: clean passthrough write — externalId + email", () => {
    expect(out).toContain("externalId: record.externalId,");
    expect(out).toContain("email: record.email,");
  });

  it("returns the { id, saved } shape in upsertByExternalId", () => {
    expect(out).toContain("return { id: proj.id, saved: record };");
  });

  it("contains NO ` as ` cast anywhere", () => {
    expect(codeOnly(out).includes(" as ")).toBe(false);
  });

  it("emits no FK SEAM when there are no FK keys", () => {
    expect(out).not.toContain("TODO(author)");
    expect(out).not.toContain("SEAM (FK external key");
  });

  it("omits userId from the write when the entity declares no user_id field", () => {
    const writeBlock = out.slice(
      out.indexOf("export function defaultContactBuildWrite("),
      out.indexOf("export function defaultContactToCanonicalView("),
    );
    expect(writeBlock).not.toContain("userId");
  });

  // #491: the Canonical alias is DELETED — replaced by the generic default + subclass type-arg.
  it("does NOT emit a ContactCanonical alias (replaced by generic TCanonical default)", () => {
    expect(out).not.toContain("export type ContactCanonical =");
  });
});

