describe("generateSinkBase — precondition (pattern: Integrated gate)", () => {
  it("hard-errors for a non-Integrated pattern, naming the entity + pattern: Integrated", () => {
    expect(() =>
      generateSinkBase(contactInput({ pattern: "Base" })),
    ).toThrow(/contact/);
    expect(() =>
      generateSinkBase(contactInput({ pattern: "Base" })),
    ).toThrow(/pattern: Integrated/);
  });

  it("hard-errors for Activity / Metadata / Knowledge patterns too", () => {
    for (const pattern of ["Activity", "Metadata", "Knowledge"]) {
      expect(() => generateSinkBase(contactInput({ pattern }))).toThrow(
        /pattern: Integrated/,
      );
    }
  });
});

