// ============================================================================
// generateSinkSubclass — emit-once subclass file
// ============================================================================

describe("generateSinkSubclass — subclass structure", () => {
  const out = generateSinkSubclass(contactInput());

  it("emits `export class ContactSink extends ContactSinkBase {`", () => {
    expect(out).toContain(
      "export class ContactSink extends ContactSinkBase {",
    );
  });

  it("carries the two one-line seam wirings (NOT an empty body)", () => {
    // The seams are abstract on the base, so an empty body would not compile.
    expect(out).toContain("return defaultContactToCanonicalView(row);");
    expect(out).toContain("return defaultContactBuildWrite(record);");
  });

  it("imports ContactSinkBase + both default functions from ./<entity>.sink.generated", () => {
    expect(out).toContain("from './contact.sink.generated'");
    expect(out).toContain("ContactSinkBase,");
    expect(out).toContain("defaultContactToCanonicalView,");
    expect(out).toContain("defaultContactBuildWrite,");
  });

  it("imports projection and write types from the repo specifier", () => {
    // The subclass uses `import type { ContactIntegrationProjection, ContactIntegrationWrite }`
    // (the `type` modifier is on the import statement, not each identifier).
    expect(out).toContain("ContactIntegrationProjection,");
    expect(out).toContain("ContactIntegrationWrite,");
    expect(out).toContain("from '../../../crm/contacts/contact.repository'");
  });

  it("does NOT carry the CODEGEN-SCAFFOLD-V1 sentinel", () => {
    expect(out).not.toContain("<CODEGEN-SCAFFOLD-V1>");
  });

  it("does NOT carry machinery (integrationUpsertOne / findByExternalIdProjected)", () => {
    // Machinery lives in the @generated base — NOT duplicated in the subclass.
    // Note: softDeleteByExternalId appears in the subclass comment (as an override hint),
    // so we only check that the repo call is not there, not the name itself.
    expect(out).not.toContain("integrationUpsertOne");
    expect(out).not.toContain("findByExternalIdProjected");
    expect(out).not.toContain("this.repo.softDeleteByExternalId");
  });

  it("does NOT carry the mechanical write or view body", () => {
    // The mapping lives in the standalone default functions in the base file.
    expect(out).not.toContain("externalId: record.externalId");
    expect(out).not.toContain("id: row.id");
  });

  it("contains NO ` as ` cast", () => {
    expect(codeOnly(out).includes(" as ")).toBe(false);
  });

  it("does NOT carry @generated banner (it is emit-once, author-owned)", () => {
    expect(out).not.toContain("@generated by @pattern-stack/codegen");
  });
});

