describe("fkWriteKey — contract test (mirrors processBelongsTo:447-460)", () => {
  it("non-self single-word: target 'account' → accountExternalId", () => {
    expect(fkWriteKey("account", "account_id", false)).toBe(
      "accountExternalId",
    );
  });

  it("non-self multi-word: target 'sales_account' → sales_accountExternalId (snake retained)", () => {
    expect(fkWriteKey("sales_account", "sales_account_id", false)).toBe(
      "sales_accountExternalId",
    );
  });

  it("self-FK: foreign_key 'parent_account_id', target 'account' → parentAccountExternalId", () => {
    expect(fkWriteKey("account", "parent_account_id", true)).toBe(
      "parentAccountExternalId",
    );
  });

  it("self-FK irregular plural: target 'company', fk 'parent_company_id' → parentCompanyExternalId", () => {
    expect(fkWriteKey("company", "parent_company_id", true)).toBe(
      "parentCompanyExternalId",
    );
  });
});

// ============================================================================
// #488 — Find-side projection: typed view, null-preserving bare passthrough
// (now in `defaultContactToCanonicalView`)
// ============================================================================

/** Extract the body of defaultContactToCanonicalView from the base file. */
function viewFnBody(out: string, entityClass: string): string {
  const marker = `export function default${entityClass}ToCanonicalView(`;
  const start = out.indexOf(marker);
  // Find the closing `}` of the function — next top-level `\nexport` or end of string.
  const nextExport = out.indexOf("\nexport", start + marker.length);
  return out.slice(start, nextExport === -1 ? undefined : nextExport);
}

describe("generateSinkBase — #488 Test 1: explicit view, not bare return row", () => {
  const out = generateSinkBase(contactInput());
  const body = viewFnBody(out, "Contact");

  it("null-guard: if (row === null) return null — NOT present in standalone function (null-guard is on base's findByExternalId)", () => {
    // The standalone function does NOT null-guard (the base method does that before calling it).
    expect(body).not.toContain("if (row === null)");
  });

  it("builds an explicit view object: const view: ContactIntegrationProjection = {", () => {
    expect(body).toContain("const view: ContactIntegrationProjection = {");
  });

  it("enumerates id: row.id", () => {
    expect(body).toContain("id: row.id,");
  });

  it("enumerates externalId: row.externalId", () => {
    expect(body).toContain("externalId: row.externalId,");
  });

  it("returns view", () => {
    expect(body).toContain("return view;");
    expect(body).not.toContain("return row;");
  });
});

