// ============================================================================
// #490 — delete:noop and deleteMode: 'delegate' | 'noop'
// (now in the CONCRETE softDeleteByExternalId on the base — not a seam)
// ============================================================================

/** Extract the softDeleteByExternalId body from the base file. */
function deleteMethodBody(out: string): string {
  const start = out.indexOf("async softDeleteByExternalId(");
  const end = out.indexOf("\n  }\n", start);
  return out.slice(start, end + 4);
}

describe("generateSinkBase — #490 deleteMode: 'delegate' (default — unchanged behavior)", () => {
  const out = generateSinkBase(contactInput());

  it("softDeleteByExternalId delegates to repo.softDeleteByExternalId (deleteMode absent → delegate)", () => {
    expect(out).toContain(
      "return this.repo.softDeleteByExternalId(externalId, this.provider);",
    );
  });

  it("no 'delete:noop' comment when delegating", () => {
    expect(deleteMethodBody(out)).not.toContain("// delete:noop");
  });
});

describe("generateSinkBase — #490 deleteMode: 'delegate' (explicit)", () => {
  const out = generateSinkBase(contactInput({ deleteMode: "delegate" }));

  it("softDeleteByExternalId delegates to repo when deleteMode: 'delegate'", () => {
    expect(out).toContain(
      "return this.repo.softDeleteByExternalId(externalId, this.provider);",
    );
  });
});

describe("generateSinkBase — #490 deleteMode: 'noop'", () => {
  const out = generateSinkBase(contactInput({ deleteMode: "noop" }));

  it("softDeleteByExternalId body is 'return null;' (not repo delegation)", () => {
    expect(deleteMethodBody(out)).toContain("return null;");
  });

  it("softDeleteByExternalId body does NOT call repo.softDeleteByExternalId", () => {
    expect(deleteMethodBody(out)).not.toContain("repo.softDeleteByExternalId");
  });

  it("noop body has an explaining comment (delete:noop / tombstone-preserving)", () => {
    expect(deleteMethodBody(out)).toContain("delete:noop");
  });

  it("contains NO ` as ` cast (noop path)", () => {
    expect(codeOnly(out).includes(" as ")).toBe(false);
  });

  it("find-side and upsert-side are unchanged when deleteMode: 'noop'", () => {
    expect(out).toContain("this.repo.findByExternalIdProjected(externalId, this.provider)");
    expect(out).toContain("this.repo.integrationUpsertOne(this.buildWrite(record), this.provider)");
  });
});

