describe("generateSinkBase — #490 excluded field absent from write object, present in find view", () => {
  const out = generateSinkBase(
    contactInput({
      entityName: "message",
      entityClass: "Message",
      copyThroughFields: [
        { camelName: "body", tsType: "string" },
        // conversationExternalId intentionally absent — excluded from write surface.
      ],
      viewCopyThroughFields: [
        { camelName: "body", tsType: "string" },
        { camelName: "conversationExternalId", tsType: "string | null" },
      ],
      fkExternalKeys: [],
    }),
  );

  it("the write function enumerates body: record.body", () => {
    const buildWriteFn = out.slice(
      out.indexOf("export function defaultMessageBuildWrite("),
      out.indexOf("export function defaultMessageToCanonicalView("),
    );
    expect(buildWriteFn).toContain("body: record.body,");
  });

  it("the write function does NOT enumerate conversationExternalId", () => {
    const buildWriteFn = out.slice(
      out.indexOf("export function defaultMessageBuildWrite("),
      out.indexOf("export function defaultMessageToCanonicalView("),
    );
    expect(buildWriteFn).not.toContain("conversationExternalId");
  });

  it("the find view DOES enumerate conversationExternalId: row.conversationExternalId (Gate 2.5 §3c inverted)", () => {
    expect(viewFnBody(out, "Message")).toContain(
      "conversationExternalId: row.conversationExternalId,",
    );
  });

  it("contains NO ` as ` cast", () => {
    expect(codeOnly(out).includes(" as ")).toBe(false);
  });
});

